// Normalise the payload regardless of WhatsApp provider (Meta, Twilio, etc.)
const body = $input.first().json;

// --- Meta Cloud API format ---
let phone = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.from;
let text  = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.text?.body;

// --- Twilio format fallback ---
if (!phone) phone = body?.From || body?.from;
if (!text)  text  = body?.Body  || body?.body  || body?.text;

// --- Raw payload fallback (direct POST from n8n test) ---
if (!phone) phone = body?.patient_phone;
if (!text)  text  = body?.message_body || body?.body;

const clinicId  = body?.clinic_id  || "c0000000-0000-0000-0000-000000000001";
const direction = body?.direction  || "inbound";

if (!phone || !text) {
  throw new Error(`Cannot extract phone or message from payload: ${JSON.stringify(body)}`);
}

return [{ json: { clinic_id: clinicId, patient_phone: phone, direction, message_body: text } }];
